targets.query:
from(bucket: "urban_raw")
    |> range(start: -35d)
    |> filter(fn: (r) =>
        r._measurement == "urban_telemetry" and
        r._field == "${metric}"
    )
    |> group(columns: [])
    |> last()
    |> map(fn: (r) => ({
        _time: now(),
        _value: float(v: uint(v: now()) - uint(v: r._time)) / 1000000000.0
    }))
    |> yield(name: "raw_age_seconds")

from(bucket: "urban_alerts")
    |> range(start: v.timeRangeStart, stop: v.timeRangeStop)
    |> filter(fn: (r) =>
        r._measurement == "urban_alerts" and
        r._field == "severity_level" and
        r.metric == "${metric}" and
        r.borough =~ /^(${borough:regex})$/ and
        r.zone_type =~ /^(${zone_type:regex})$/
    )
    |> group(columns: ["grid_id"])
    |> reduce(
        identity: {
            alert_count: 0,
            max_severity: 0
        },
        fn: (r, accumulator) => ({
            alert_count: accumulator.alert_count + 1,
            max_severity: if int(v: r._value) > accumulator.max_severity then int(v: r._value) else accumulator.max_severity
        })
    )
    |> group(columns: [])
    |> keep(columns: ["grid_id", "alert_count", "max_severity"])
    |> yield(name: "metric_zone_alerts")
